/**
 * retryWithBackoff
 *
 * Retry utility with exponential backoff for async operations.
 * Useful for network requests, file operations, etc.
 */
export interface RetryOptions {
    /**
     * Maximum number of retry attempts
     * @default 3
     */
    maxRetries?: number;
    /**
     * Initial delay in milliseconds before first retry
     * @default 1000
     */
    baseDelay?: number;
    /**
     * Maximum delay in milliseconds (caps exponential growth)
     * @default 10000
     */
    maxDelay?: number;
    /**
     * Multiplier for exponential backoff
     * @default 2
     */
    backoffMultiplier?: number;
    /**
     * Function to determine if error is retryable
     * @default () => true (retry all errors)
     */
    shouldRetry?: (error: Error, attempt: number) => boolean;
    /**
     * Callback on each retry attempt
     */
    onRetry?: (error: Error, attempt: number, delay: number) => void;
}
/**
 * Retry an async function with exponential backoff
 *
 * @example
 * ```ts
 * const result = await retryWithBackoff(
 *   () => fetch('https://api.example.com'),
 *   { maxRetries: 3, baseDelay: 1000 }
 * );
 * ```
 */
export declare function retryWithBackoff<T>(fn: () => Promise<T>, options?: RetryOptions): Promise<T>;
/**
 * Retry with timeout
 * Combines retry logic with a timeout
 *
 * @example
 * ```ts
 * const result = await retryWithTimeout(
 *   () => fetch('https://api.example.com'),
 *   { timeout: 5000, maxRetries: 3 }
 * );
 * ```
 */
export declare function retryWithTimeout<T>(fn: () => Promise<T>, options?: RetryOptions & {
    timeout?: number;
}): Promise<T>;
/**
 * Check if error is a network error
 * Useful for shouldRetry callback
 */
export declare function isNetworkError(error: Error): boolean;
/**
 * Check if error is retryable HTTP status
 * Useful for shouldRetry callback
 */
export declare function isRetryableHttpStatus(status: number): boolean;
